const MainContent = () => (
    <div>
        <h2>Technical articles</h2>
        <ol>
           {articles.map(({ link, title })=><Link link={link} title={title}/>)}
        </ol>
    </div>
)

const Link = ({ link, title }) => {
    return (
    <li><a target="_blank" href={link}>{title}</a></li>
    )
}

const articles = [
